#include "kernel_operator.h"

constexpr int32_t BUFFER_NUM = 2;

class KernelCa6k04670Custom {
public:
  __aicore__ inline KernelCa6k04670Custom() {}

  __aicore__ inline void Init(GM_ADDR x, GM_ADDR y, GM_ADDR weight, GM_ADDR bias,
                              uint32_t totalLength, uint32_t tileLength,
                              uint32_t N, uint32_t C, uint32_t H, uint32_t W,
                              float eps) {
    totalLen_ = totalLength;
    tileLen_ = tileLength;
    N_ = N;
    C_ = C;
    H_ = H;
    W_ = W;
    eps_ = eps;
    spatialLen_ = H * W;
    xGm_.SetGlobalBuffer((__gm__ float*)x, totalLen_);
    yGm_.SetGlobalBuffer((__gm__ float*)y, totalLen_);
    weightGm_.SetGlobalBuffer((__gm__ float*)weight, C_);
    biasGm_.SetGlobalBuffer((__gm__ float*)bias, C_);

    pipe_.InitBuffer(inQueueX_, BUFFER_NUM, tileLen_ * sizeof(float));
    pipe_.InitBuffer(outQueueY_, BUFFER_NUM, tileLen_ * sizeof(float));
    pipe_.InitBuffer(tmpQueue_, 1, tileLen_ * sizeof(float));
    pipe_.InitBuffer(s1Queue_, 1, 1 * sizeof(float));
    pipe_.InitBuffer(s2Queue_, 1, 1 * sizeof(float));
  }

  __aicore__ inline void Process() {
    if (totalLen_ == 0 || tileLen_ == 0) return;

    const uint32_t blockNum = static_cast<uint32_t>(AscendC::GetBlockNum());
    const uint32_t blockIdx = static_cast<uint32_t>(AscendC::GetBlockIdx());

    for (uint32_t c = blockIdx; c < C_; c += blockNum) {
      float mean, var;
      ComputeSumAndSumSq(c, mean, var);
      NormalizeChannel(c, mean, var);
    }
  }

private:
  __aicore__ inline void ComputeSumAndSumSq(uint32_t c, float &mean, float &var) {
    float sum = 0.0f;
    float sumSq = 0.0f;
    uint32_t channelOffset = c * spatialLen_;

    for (uint32_t n = 0; n < N_; ++n) {
      uint32_t batchOffset = n * C_ * spatialLen_;
      uint32_t base = batchOffset + channelOffset;
      uint32_t remaining = spatialLen_;
      uint32_t tileStart = 0;

      while (remaining > 0) {
        uint32_t curLen = (remaining > tileLen_) ? tileLen_ : remaining;

        AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
        AscendC::DataCopy(xLocal, xGm_[base + tileStart], curLen);
        inQueueX_.EnQue(xLocal);

        xLocal = inQueueX_.DeQue<float>();
        AscendC::LocalTensor<float> tLocal = tmpQueue_.AllocTensor<float>();
        AscendC::Mul(tLocal, xLocal, xLocal, curLen);

        AscendC::LocalTensor<float> sumLocal = s1Queue_.AllocTensor<float>();
        AscendC::LocalTensor<float> sumSqLocal = s2Queue_.AllocTensor<float>();
        AscendC::ReduceSum(sumLocal, xLocal, nullptr, 0);
        AscendC::ReduceSum(sumSqLocal, tLocal, nullptr, 0);

        sum += sumLocal.GetValue(0);
        sumSq += sumSqLocal.GetValue(0);

        s1Queue_.FreeTensor(sumLocal);
        s2Queue_.FreeTensor(sumSqLocal);
        tmpQueue_.FreeTensor(tLocal);
        inQueueX_.FreeTensor(xLocal);

        tileStart += curLen;
        remaining -= curLen;
      }
    }

    float totalElements = N_ * spatialLen_;
    mean = sum / totalElements;
    float sqMean = sumSq / totalElements;
    var = sqMean - mean * mean;
  }

  __aicore__ inline void NormalizeChannel(uint32_t c, float mean, float var) {
    AscendC::LocalTensor<float> varLocal = s1Queue_.AllocTensor<float>();
    varLocal.SetValue(0, var + eps_);
    AscendC::LocalTensor<float> invStdLocal = s2Queue_.AllocTensor<float>();
    AscendC::Sqrt(invStdLocal, varLocal, 1);
    float invStd = 1.0f / invStdLocal.GetValue(0);
    s1Queue_.FreeTensor(varLocal);
    s2Queue_.FreeTensor(invStdLocal);

    float w = weightGm_.GetValue(c);
    float b = biasGm_.GetValue(c);
    uint32_t channelOffset = c * spatialLen_;

    for (uint32_t n = 0; n < N_; ++n) {
      uint32_t batchOffset = n * C_ * spatialLen_;
      uint32_t base = batchOffset + channelOffset;
      uint32_t remaining = spatialLen_;
      uint32_t tileStart = 0;

      while (remaining > 0) {
        uint32_t curLen = (remaining > tileLen_) ? tileLen_ : remaining;

        AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
        AscendC::DataCopy(xLocal, xGm_[base + tileStart], curLen);
        inQueueX_.EnQue(xLocal);

        xLocal = inQueueX_.DeQue<float>();
        AscendC::LocalTensor<float> yLocal = outQueueY_.AllocTensor<float>();
        AscendC::LocalTensor<float> tLocal = tmpQueue_.AllocTensor<float>();

        AscendC::Adds(tLocal, xLocal, -mean, curLen);
        AscendC::Muls(tLocal, tLocal, invStd, curLen);
        AscendC::Muls(yLocal, tLocal, w, curLen);
        AscendC::Adds(yLocal, yLocal, b, curLen);

        tmpQueue_.FreeTensor(tLocal);
        outQueueY_.EnQue<float>(yLocal);
        inQueueX_.FreeTensor(xLocal);

        yLocal = outQueueY_.DeQue<float>();
        AscendC::DataCopy(yGm_[base + tileStart], yLocal, curLen);
        outQueueY_.FreeTensor(yLocal);

        tileStart += curLen;
        remaining -= curLen;
      }
    }
  }

private:
  AscendC::TPipe pipe_;
  AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> inQueueX_;
  AscendC::TQue<AscendC::TPosition::VECOUT, BUFFER_NUM> outQueueY_;
  AscendC::TQue<AscendC::TPosition::VECCALC, 1> tmpQueue_;
  AscendC::TQue<AscendC::TPosition::VECCALC, 1> s1Queue_;
  AscendC::TQue<AscendC::TPosition::VECCALC, 1> s2Queue_;
  AscendC::GlobalTensor<float> xGm_;
  AscendC::GlobalTensor<float> yGm_;
  AscendC::GlobalTensor<float> weightGm_;
  AscendC::GlobalTensor<float> biasGm_;
  uint32_t totalLen_{0};
  uint32_t tileLen_{0};
  uint32_t N_{0}, C_{0}, H_{0}, W_{0};
  uint32_t spatialLen_{0};
  float eps_{1e-5f};
};

